code = """import json, pandas as pd, re

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r', encoding='utf-8') as f:
            return json.load(f)
    return v

books = load_records(var_call_bmxNzDYQOhjZS7WaT0PhquBT)
avg5 = load_records(var_call_HpcqQqMVKqVwSCHmDijXMHvw)

bdf = pd.DataFrame(books)
adf = pd.DataFrame(avg5)

# normalize ids for fuzzy join (bookid_### <-> purchaseid_###)
get_num = lambda s: int(re.search(r'(\d+)$', str(s)).group(1)) if re.search(r'(\d+)$', str(s)) else None
bdf['id_num'] = bdf['book_id'].map(get_num)
adf['id_num'] = adf['purchase_id'].map(get_num)

m = bdf.merge(adf, on='id_num', how='inner')

# English-language filter from details text
m['is_english'] = m['details'].fillna('').str.contains(r'\bEnglish\b', case=False, regex=True)
res = m[m['is_english']].copy()

# output fields
res['n_reviews'] = res['n_reviews'].astype(int)
res = res.sort_values(['title','book_id'])
out = res[['title','author','book_id','purchase_id','avg_rating','n_reviews']].to_dict(orient='records')
print('__RESULT__:')
print(json.dumps(out, ensure_ascii=False))"""

